"import os

possible_paths = [
    os.path.expandvars(r'%APPDATA%\Claude'),
    os.path.expandvars(r'%LOCALAPPDATA%\Programs\Claude'),
    os.path.expandvars(r'%LOCALAPPDATA%\Programs\claude-desktop'),
    os.path.expandvars(r'%LOCALAPPDATA%\claude-desktop-updater'),
]

for p in possible_paths:
    print(f"Path: {p}")
    if os.path.exists(p):
        print("Exists. Directory contents:")
        try:
            for item in os.listdir(p):
                full = os.path.join(p, item)
                if os.path.isdir(full):
                    print(f"  [DIR]  {item}")
                else:
                    print(f"  [FILE] {item} ({os.path.getsize(full)} bytes)")
        except Exception as e:
            print(f"  Error: {e}")
    else:
        print("Does not exist.")
    print("-" * 40)
"

"import os

search_paths = [
    os.path.expandvars(r'%LOCALAPPDATA%'),
    os.path.expandvars(r'%APPDATA%'),
    r'C:\Program Files',
    r'C:\Program Files (x86)',
]

print("Searching for Claude.exe or installation folder...")
found = []

for base_path in search_paths:
    if not os.path.exists(base_path):
        continue
    print(f"Searching in {base_path}...")
    for root, dirs, files in os.walk(base_path):
        # Skip directories to speed up
        for skip in ['Microsoft', 'Google', 'Adobe', 'NVIDIA', 'Dropbox', 'Android', 'Gradle', 'Common Files']:
            if skip in dirs:
                dirs.remove(skip)

        for file in files:
            if file.lower() == 'claude.exe':
                full_path = os.path.join(root, file)
                print(f"FOUND CLAUDE: {full_path}")
                found.append(full_path)

if not found:
    print("Could not find Claude.exe in common locations.")
"
